insert into curriculum.course_version_graphemes (
  course_version_id,
  grapheme_id,
  romanization,
  pronunciation_hint,
  mnemonic,
  position,
  pedagogical_group_key,
  pedagogical_group_label,
  details,
  tags
)
values
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '155d0198-aac0-5a9d-a8ab-fb839ccab4f9'::uuid, 'm', 'm as in "mother"', 'ม is ม ม้า (mor ma, horse). Picture the tall middle stroke as a horse''s neck and the small loop as its head, then tie that horse word to the m sound.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'f9127074-00ba-5295-aac0-01022b890b89'::uuid, 'aa', 'long "aa" as in "father"', 'า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.', 'right', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '0323b564-2380-5449-aa92-cc5f6772a1a0'::uuid, 'g/k', 'hard g/k sound; final ก closes like "k"', 'ก is ก ไก่ (gor gai, chicken), the classic Thai alphabet anchor. Picture the hook as the chicken''s head and beak for the hard g/k sound.', 'standalone', null, null, '{"class":"mid"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '4cd66937-cf81-571b-ae18-6ae1055dd3ae'::uuid, 'd/t', 'd as in "dog" at the start; clipped t at the end', 'ด is ด เด็ก (dor dek, child). Picture the loop as a child''s round head beside a small body; ด starts words with d and closes as t.', 'standalone', null, null, '{"class":"mid"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'ee1f3cf4-8315-510e-a613-dfc5ec42d2f5'::uuid, 'ii', 'long "ee" as in "see"', 'ี is ิ with an extra length stroke on top. That extra stroke is your clue to hold the sound longer: short i becomes long ii.', 'above', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '02613447-13c2-5348-aad7-857e5e6ae103'::uuid, 'n', 'n as in "no"', 'น is น หนู (nor nuu, mouse). Picture the curl as a little mouse body and tail, and use หนู to lock in the n sound.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '7dba55ea-1ad4-5d3c-a85d-9c7b7a6f3553'::uuid, 'i', 'short "i" as in "sit"', 'ิ is the short i mark above the consonant. It has no extra length stroke, so keep the vowel quick in words like กิน.', 'above', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '5b347f02-b891-5f29-ad35-11da91e7b87c'::uuid, 't', 't as in "stop" (unaspirated)', 'ต is ต เต่า (tor tao, turtle). Picture the rounded part as a turtle shell with a small head, then read it as the plain t/dt sound.', 'standalone', null, null, '{"class":"mid"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '50ada581-79e7-5549-a9a8-77693569d9b8'::uuid, 'l', 'l as in "love"', 'ล is ล ลิง (lor ling, monkey). Let the long lower curve be the monkey''s tail, and connect ลิง to the l sound.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'dddb2e02-9aa3-5dde-a2ab-25524fc96559'::uuid, 'b/p', 'b as in "bat" at the start; clipped p at the end', 'บ is บ ใบไม้ (bor bai mai, leaf). The open bowl shape can hold a leaf, and ใบไม้ gives you the b sound at the start.', 'standalone', null, null, '{"class":"mid"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '1684cb46-8524-51a4-ad84-8dd2fe3b46be'::uuid, 'ae', 'long "ae" as in the vowel of "care"', 'แ is a double left-side vowel. The two front posts tell your eye to look left first, then come back to the consonant for ae.', 'left', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '13e7c7cd-283c-5d0b-a9cc-ce5b3831e495'::uuid, 'mai ek', 'first tone mark written above the consonant', '่ is mai ek, the first tone mark. It is one small stroke above the consonant, so read it as a compact tone cue.', 'above', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '76e47267-9161-5fee-a1e7-f698d88554f8'::uuid, 'r', 'r as in "run" at the start; n at the end in some words', 'ร is ร เรือ (ror ruea, boat). Picture the main curve as a boat hull rocking forward, and use เรือ to remember the r sound.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '56d6049c-5c20-5436-a5d0-37ea5d73fe05'::uuid, 'mai tho', 'second tone mark written above the consonant', '้ is mai tho, the second tone mark. It looks heavier than mai ek, a good cue that this is the second above-letter tone mark.', 'above', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '9593d6a6-13bb-563d-a33d-b01dd74e3528'::uuid, 'ch', 'ch as in "check"', 'ช is ช ช้าง (chor chaang, elephant). Picture the long dropping stroke as an elephant trunk, and use ช้าง for the ch sound.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'a57ca296-4754-50f0-aad0-9856fff5c81d'::uuid, 'u', 'short "u" as in "put"', 'ุ is the short u mark tucked under the consonant. Low on the page and short in sound: use it for the quick u in ชุด.', 'below', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'ae26196d-7a39-57e3-a8c4-061567bf9167'::uuid, 's', 's as in "sun"', 'ส is ส เสือ (sor suea, tiger). The pointed, striped-looking shape can cue a tiger, and เสือ starts with the crisp s sound.', 'standalone', null, null, '{"class":"high"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'd9bb0ca4-5089-5ba0-aa79-1bdd09ba86ad'::uuid, 'kh', 'kh with a puff of air, like the start of "khaki"', 'ข is ข ไข่ (khor khai, egg). Picture the open curve as an eggshell; ไข่ starts with the puffed kh sound that separates ข from ก.', 'standalone', null, null, '{"class":"high"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '5e1b543b-6be0-5279-a812-4ec61ce2b1dc'::uuid, 'w', 'w as in "water"; can help form vowel glides', 'ว is ว แหวน (wor waen, ring). The rounded curl looks like a ring, and แหวน gives you the w sound.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '98079396-6adf-5409-a63c-121764a3840e'::uuid, 'h', 'h as in "hello"; often used as a leading tone helper', 'ห is ห หีบ (hor hiip, chest). Picture the tall shape as a chest with a lid; in words like หมู, this h-letter can also guide the tone.', 'standalone', null, null, '{"class":"high"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '6cbd6547-63c8-52cd-a2e5-378aa42e3e46'::uuid, 'uu', 'long "oo" as in "food"', 'ู is the long uu mark below the consonant. It is like ุ with a longer lower tail, so let the oo sound run longer.', 'below', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'd6388a97-b0cb-5594-af90-48fd4c770e0f'::uuid, 'silent carrier', 'placeholder consonant used when a syllable begins with a vowel sound', 'อ is อ อ่าง (or aang, basin). The round basin shape can hold a vowel, which fits its job as a silent carrier in อา and อาหาร.', 'standalone', null, null, '{"class":"mid"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'da8975d2-f60a-59f9-a1d2-f55df44b6bfa'::uuid, 'ph', 'ph with a puff of air, like the start of "photo" without the f sound', 'ผ is ผ ผึ้ง (phor phueng, bee). Picture the open shape as wings and body; ผึ้ง starts with the puffed ph sound.', 'standalone', null, null, '{"class":"high"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '6655bad5-f432-5868-aa67-e7247253802f'::uuid, 'a', 'short "a" as in "cut"', 'ั is the short a cap above the consonant. It sits close and quick, just like the clipped a in ผัด and ผัก.', 'above', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'bda65912-fa0a-5328-a7d4-302245d61c3e'::uuid, 'ng', 'ng as in "singer"; used at the start or end of a syllable', 'ง is ง งู (ngor nguu, snake). Picture the curving body of a snake; ง makes the ng sound that English only uses at the ends of words.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'cf8eaddc-cd8e-55ca-a652-237794f23e8b'::uuid, 'th', 'th with a puff of air, like the "t" in "top" (not the th in "the")', 'ท is ท ทหาร (thor thahaan, soldier). Picture a soldier standing tall; ท gives the aspirated th sound with a clear puff of air.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'e4575690-2031-5d02-a9ed-227f99686432'::uuid, 'j', 'j as in "jar", but lighter and unaspirated', 'จ is จ จาน (jor jaan, plate). Picture a round dinner plate; จ gives a light, crisp j sound.', 'standalone', null, null, '{"class":"mid"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'f4bda34e-a00e-53ac-a756-196e4fd86dcb'::uuid, 'a', 'short "a" cut off by a quick glottal stop, like a clipped "ah!"', 'ะ is the two-dot short-a written to the right of the consonant. It ends the syllable abruptly, like catching your breath after ''ah''.', 'right', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'd930649b-b987-5148-a7d1-8aaabef44060'::uuid, 'e', 'long "e" as in "they"', 'เ is the long-e vowel written BEFORE the consonant, even though you say the consonant first. Spot เ, jump to the consonant after it, then add the e.', 'left', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'd636b36c-e319-5414-ad3e-8657562bd576'::uuid, 'ai', 'the "ai" sound as in "Thai"', 'ไ (ไม้มลาย, mai malai) is the common ai vowel, written before the consonant. Note the small flag curling off the top.', 'left', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '54ee9c51-1ccc-59bb-a95d-2e6f8d66ecf1'::uuid, 'ai', 'the same "ai" sound as ไ', 'ใ (ไม้ม้วน, mai muan) sounds identical to ไ but appears in only about 20 specific words you memorize. Note the curled-in top.', 'left', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '6450d4bf-a0e5-5f34-aaad-6b404ea92b59'::uuid, 'o', 'long "o" as in "go"', 'โ is the long-o vowel with a tall vertical stroke, written before the consonant. Like เ and ไ, read the consonant after it first.', 'left', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '1468f8a2-d91f-5127-ac8d-e40de6f54950'::uuid, 'bp', 'a tight, unaspirated p, like the p in "spin" (between English b and p)', 'ป is ป ปลา (bpor bplaa, fish). Picture a tall fish standing on its tail; ป is the unaspirated p that pairs with the dt sound of ต.', 'standalone', null, null, '{"class":"mid"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'f08f3ab4-ea11-53cf-a8b5-c3ea310041b1'::uuid, 'y', 'y as in "yes"; at the end of a syllable it forms a glide like the "y" in "boy"', 'ย is ย ยักษ์ (yor yak, giant). Picture a towering giant; ย gives the y sound at the start and a y-glide at the end.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]);

insert into curriculum.tips (
  id,
  course_version_id,
  key,
  title,
  body,
  display,
  sections,
  metadata,
  created_at
)
values
  ('32886e36-2a9f-527e-a390-d7b1f4af98a8'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'sound-romanization', 'Romanization', 'This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound.', 'popover', '[]'::jsonb, '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('03ce635f-04a2-5bf9-a778-bfdb1e47f142'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'pronunciation-by-position', 'Sound changes by position', 'Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end.', 'popover', '[]'::jsonb, '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('8c88971c-0b65-50b9-aef3-15a3a67a6231'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'consonant-class-tones', 'Consonant class & tone', 'Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.', 'modal', '[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]'::jsonb, '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('775872e7-e41b-58b3-a76c-891615eb8c51'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'letter-type-vowel', 'Vowel', 'Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order.', 'popover', '[]'::jsonb, '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('735caac2-4569-5f75-a419-a391fbce94e3'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'letter-type-tone-mark', 'Tone mark', 'Tone marks are small symbols written above a consonant to override the default tone of the syllable. Thai has two common tone marks (mai ek ่ and mai tho ้). Their effect depends on the consonant class of the syllable they modify.', 'popover', '[]'::jsonb, '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('012f7a10-4d51-547b-a575-429ba601b104'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'vowel-position', 'Vowel position', 'Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position.', 'popover', '[]'::jsonb, '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz);

