  ('f932c1d2-de4f-5a71-a5c9-aa0acbd6f665'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'word-0e14-0e35-0e21-0e32-0e01', 'ดีมาก', 'ดีมาก', 'very good', 'dii maak', 'daily', null, '{"sourceType":"phrase"}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
