  ('142df77a-2c8f-5948-af3f-26e5778ff982'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'word-0e14-0e34-0e19', 'ดิน', 'ดิน', 'soil / earth', 'din', 'daily', null, '{"sourceType":"real"}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('86538398-e5ca-5917-a618-e7586d124894'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'word-0e19-0e32', 'นา', 'นา', 'rice field', 'naa', 'place', null, '{"sourceType":"real"}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
