  ('d1d3fe12-62f5-5fa6-ab64-c59a5156b603'::uuid, '3298e2e3-5f8b-5593-a778-1eef71986d23'::uuid, 'practice_core', 5, true, '{"sourceType":"real"}'::jsonb),
