insert into curriculum.orthography_rules (
  id,
  course_version_id,
  key,
  name,
  short_description,
  explanation,
  metadata,
  created_at
)
values
  ('671ddf5e-f429-5a7b-a9a1-f88d61020189'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'long-aa-right', 'Long า Stretches Right', 'า is written after the consonant and gives you a long aa sound', 'Thai often places vowels around a consonant instead of in a straight line like English. The long vowel า sits to the right of the consonant and stretches the syllable into a clear aa sound.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('884e5d37-78f3-5c0d-abda-be4ea9b3b8a5'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'final-k-stop', 'Final ก Ends in a Stop', 'At the end of a syllable, ก closes sharply as a k sound', 'Thai final consonants are often clipped. In มาก, the last ก does not open into a full English g. It closes the syllable with a short unreleased k sound.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('4438b9e5-0dad-5fb9-a65e-f29a4cc6a62a'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'implied-short-o', 'Two Bare Consonants Often Add a Short "o"', 'When Thai stacks two consonants with no written vowel, a short o often appears between them', 'Once you know a few consonants, you can read more than long-vowel forms. In many short Thai syllables, two consonants written together with no vowel sign are read with an implied short o sound between them.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('08d94ec2-a20e-5de1-a856-70fd4d44ffe2'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'long-ii-above', 'Long ี Sits Above', 'ี is written above the consonant and gives you a long ee sound', 'Thai vowels are often placed above, below, or around the consonant. In ดี, the consonant comes first and the long vowel ี sits above it, so you read ด then stretch into ee.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('6d95fd8f-f8f2-57a9-a0e0-6895baa2f935'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'initial-d-sound', 'Initial ด Starts Cleanly', 'At the start of a syllable, ด gives you a plain d sound', 'Thai consonants can behave differently at the start and the end of a syllable. In ดี, ด is initial, so you read it as a straightforward d sound before the vowel.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('90dd223e-c255-5285-a129-360e6205288e'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'short-i-above', 'Short ิ Sits Above', 'The short i vowel appears above the consonant you read first', 'Thai often asks you to scan above the line as you read. In กิน, the consonant ก comes first and the short vowel ิ is written above it, giving you gi before the final consonant closes the syllable.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('23dac35f-4b61-566e-a6f9-3ba53bd27a9d'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'final-n-stays-n', 'Final น Stays N', 'At the end of a syllable, น keeps a clear n sound', 'Not every Thai final consonant gets clipped into a stop. Final น stays nasal and easy to hear, so กิน closes with a clear n sound.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('b87f5a0a-c8ed-581b-a6ec-928cce42fde3'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'hidden-vowel-market', 'Hidden Short "a" Vowel', 'When two consonants can''t blend, a short "a" hides between them', 'In Thai, when two consonants appear next to each other but can''t form a natural cluster, a short "a" sound is inserted between them. In ตลาด, the ต and ล can''t blend, so you say "tà-làat" not "tlàat". This hidden vowel is never written.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('06f3f841-d7df-5644-a11e-3c5cdebae18c'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'final-stop-market', 'Final Consonants are Stopped', 'Consonants at the end of a syllable are "swallowed"', 'When ด appears at the end of a word, it doesn''t make a full "d" sound. Instead, your tongue touches the roof of your mouth but you don''t release it. This is why ตลาด sounds like "tà-làat" and not "tà-làad".', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('6346557e-a6a4-5dac-adcd-4617cd7f09a1'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'initial-b-sound', 'Initial บ Starts With B', 'At the start of a syllable, บ gives you a plain b sound', 'Thai consonants often shift between initial and final positions. In บิน, บ comes first, so it sounds like a clean b before the short vowel and final consonant close the word.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('30f160d3-cbb7-5e8f-ae64-9be8c99ff663'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'in-frame-pattern', 'The -ิน Frame Repeats', 'Once you know a syllable frame, swapping the first consonant unlocks more words', 'กิน, บิน, and similar short words share the same short-i plus final-น frame. Thai gets much easier once you start seeing these reusable patterns instead of single isolated words.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('339f3a02-f34d-5263-a796-4d45cd2e4b7f'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'before-vowels-left', 'Some Vowels Sit on the Left', 'The vowel แ is written before the consonant you pronounce first', 'Thai does not always place vowels after the consonant. In แม่, your eye has to notice แ on the left, then come back to read ม with that vowel sound attached.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('c360364a-3f7a-5b8d-a892-563359ef7e9e'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'mai-ek-tone-mark', 'Meet Your First Tone Mark', 'Tone marks sit above the consonant and change the sound of the whole syllable', 'You do not need the full tone system at once. Start by recognizing that ่ lives above the consonant and changes the word you say. High-frequency sight words make tone marks easier to remember than abstract charts.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('ba8c4da3-023b-5812-a6fb-0c09b52ce472'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'initial-r-sound', 'Initial ร Gives You R', 'At the start of a syllable, ร is read as an r sound', 'Thai ร has a few different jobs, but in ร้าน it is straightforward: it starts the word with an r sound before the tone mark and vowel shape do the rest of the work.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('9d39de17-63e6-5cde-a43b-0d5655df93ec'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'mai-tho-above', 'Tone Marks Sit Above the Consonant', 'Even when the vowel is on the right, the tone mark still sits above the main consonant', 'In ร้าน, the long vowel า is on the right, but the tone mark ้ still sits above ร. Thai asks you to scan the whole syllable block, not just read from left to right.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('215881f9-c7b2-522c-aaea-b676d1f481a5'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'short-u-below', 'Short ุ Sits Below', 'The short u vowel is written below the consonant you pronounce first', 'Thai keeps asking you to scan vertically. In ชุด, the consonant ช comes first and the short vowel ุ is tucked underneath, so you read chu before the final consonant closes the syllable.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('707d8403-783a-58bc-a40e-f63cb7a936d5'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'dead-syllable-stop', 'Short Vowels Feel Clipped in Closed Syllables', 'A short vowel plus a final stop makes the whole word feel quick and closed', 'ชุด feels short because the vowel is short and the final consonant is stopped. This clipped rhythm shows up in lots of practical Thai words on menus and signs.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('1a204ee8-b537-5026-a80e-84c60be7b87d'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'initial-s-sound', 'Initial ส Gives You S', 'At the start of a syllable, ส is a clean s sound', 'Thai has several letters that can map to an s-like sound, but you do not need them all at once. Start with ส because it appears constantly in useful words, labels, and polite formulas.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('a81aec16-221e-590d-a79d-ca348451a472'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'final-b-to-p', 'Final บ Closes as P', 'At the end of a word, บ does not stay a full b sound', 'Like several Thai final consonants, บ gets clipped at the end of a syllable. In สิบ, your lips close for p without the full released English b sound.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('71da4ee2-bbc8-5047-a6bf-bbfd13816bfc'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'kh-vs-k', 'ข Adds Air to K', 'ข is not the same as ก; it has a stronger puff of air', 'Thai distinguishes plain k sounds from aspirated kh sounds. If you hold your hand in front of your mouth, ข pushes out a little air in a way ก does not.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('52b3fcea-a418-58db-ad81-2054c133fba1'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'aaw-glide', 'ว Can Help Build a Vowel Glide', 'In words like ข้าว, ว helps shape the ending vowel sound instead of behaving like a full separate consonant', 'Not every written consonant is heard as a clean standalone consonant. In ข้าว, ว helps form the -าว ending, so you hear a smooth glide rather than a sharp final w.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('62ade15b-2ecf-5726-a1dd-6689ff8c548e'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'leading-h-pattern', 'Leading ห Changes the Tone Pattern', 'In common words like หมู, ห helps a following low consonant behave differently', 'This is one of the Thai chunks worth learning as a whole. In words like หมู, the ห is not there to give you a full h sound before every letter. It helps control the syllable pattern of the low consonant that follows.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('d5b18e8e-9a1e-5ea5-a808-651961f8dfb4'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'long-uu-below', 'Long ู Sits Below', 'The long oo vowel is written below the consonant', 'Thai uses the space below the line too. In หมู and หู, the vowel ู sits under the consonant and gives you a long oo sound.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('12476104-aabd-52e5-ad0e-4994d23aec74'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'silent-carrier', 'อ Can Carry a Vowel Silently', 'Thai still wants a consonant slot even when the syllable begins with a vowel sound', 'In อาหาร, the first syllable sounds like aa, but Thai still writes a consonant letter to hold that opening vowel. อ acts as the carrier without adding a strong sound of its own.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('b144050a-1ef9-53f3-ae3c-d669fc4571f3'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'final-r-to-n', 'Final ร Often Sounds Like "n"', 'At the end of a syllable, ร is often heard as "n" instead of a full r', 'Thai final consonants do not always match their initial sounds. In อาหาร, the final ร is not read as a strong r. It closes the word with an n-like ending instead.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('a760feb3-b11d-5a48-aa4b-dfb7b7a0c055'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'ph-vs-b', 'ผ Gives You an Airy Ph Sound', 'ผ is not the same as บ; it starts with a stronger puff of air', 'Thai distinguishes plain b/p-like sounds from aspirated ph sounds. In ผัด, you can feel a burst of air at the start that you do not get with บ.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('80814a05-caf2-5ac2-afd4-5311e1cc970e'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'short-a-above', 'Short ั Sits Above', 'The short a vowel is written above the consonant', 'Thai uses a small mark above the consonant for the short a sound in words like ผัด. It is quicker and more clipped than the long right-side vowel า you learned earlier.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('163cd892-8102-57c0-aa71-21b8dc0c8678'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'ng-sound', 'ง Is the ng Sound', 'ง gives the ng sound at the start or end of a syllable', 'English only uses ng at the ends of words like ''song''. Thai uses ง freely, including at the start of a syllable. Either way it is the same soft nasal ng.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('75fcd479-d9cf-5987-a10f-effe48730a52'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'final-ng', 'Final ง Closes With ng', 'At the end of a syllable, ง closes it with the nasal ng', 'Final ง is extremely common in Thai. It is fully pronounced as the ng you hear at the end of ''song'', not clipped like the final stops you learned earlier.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('e0feec68-c9f5-560f-a48c-dce0e36b48ce'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'aw-vowel-or', 'อ Can Be the aw Vowel', 'After a consonant, อ gives the long aw sound', 'You met อ as a silent carrier earlier. When อ is written after a consonant with no other vowel, it instead acts as the long aw vowel you hear in ของ and รอ.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('831cdc66-6fb7-575f-acb5-7fb543f0e666'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'low-th', 'ท Is an Aspirated th', 'ท starts with a puff of air, like the t in ''top''', 'Thai ท is not the soft th in ''the''. It is a t sound released with a clear puff of air, the same way English starts the word ''top''.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('09daaa09-a96a-517d-a22c-c5b2a68c1bf9'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'th-vs-t', 'ท and ต Are Different t Sounds', 'ต is a tight, unaspirated t (dt); ท adds a puff of air', 'ต and ท both involve the tongue behind the teeth, but ต is clipped with no air (closer to a d/t blend) while ท releases a puff of air. Keeping them apart changes the word.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('d483daf3-63c0-5acc-a73d-c558c388f8af'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'j-sound', 'จ Is a Light j', 'จ gives an unaspirated j sound', 'จ is close to the English j in ''jar'' but lighter, with no puff of air. It is a mid-class consonant, which keeps its tones predictable.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('433a210b-ee14-514f-a228-9f28e323f475'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'short-a-glottal', 'ะ Is a Clipped Short a', 'ะ sits after the consonant and ends with a glottal stop', 'The ะ vowel gives a short a, then closes the syllable sharply with a glottal stop (the catch in the middle of ''uh-oh''). It is quicker than the long า.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('a2c1d059-1ef1-57a9-ab6c-a4aa2f120298'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'three-a-vowels', 'Three Ways to Write a', 'า is long; ั is short above; ะ is short with a hard stop', 'You now know all three core a-vowels: า stretches long to the right, ั is a quick short a above the consonant, and ะ is a short a after it that ends in a glottal stop.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('939342eb-ed8d-5580-a1cd-b756e757ffba'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'leading-e-vowel', 'เ Is Written Before the Consonant', 'เ appears to the left but is pronounced after the consonant', 'Some Thai vowels are written in front of their consonant even though they are spoken after it. เ is the first of these: it gives a long e, but you read the consonant that follows it first.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('6409b125-3787-5409-af45-9681cf842fdf'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'scan-left-rule', 'Scan Left for Leading Vowels', 'When a word starts with เ, read the next consonant first', 'When you see a leading vowel like เ at the front of a syllable, do not read straight across. Read the consonant after it, then wrap the vowel around. This same habit covers ไ, ใ, and โ next.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('2bcd40f2-7394-5631-a41e-47605ee7d502'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'leading-ai', 'ไ and ใ Are Leading ai Vowels', 'Both sound like ''ai'' and are written before the consonant', 'ไ and ใ are leading vowels, just like เ: written in front of the consonant, pronounced after it. Both give the same ai sound you hear in the word ''Thai''.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('203bfa56-3595-5e10-a6b0-aca06096f272'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'mai-malai-vs-muan', 'Two Spellings, One Sound', 'ไ is the common ai; ใ covers only about 20 must-know words', 'ไ (mai malai) is by far the more common spelling. ใ (mai muan) sounds exactly the same but is used in roughly 20 fixed words, such as ใจ (heart), ใหม่ (new), and ใช่ (yes). Those are worth memorizing as a set.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('615f71c4-a9dc-55aa-a872-f0955ec5ea8c'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'leading-long-o', 'โ Is a Leading Long o', 'โ sits before the consonant and gives a long o', 'โ is another leading vowel. It is written in front of the consonant and gives a clean long o, like the vowel in English ''go''.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('14b01fb1-3ab2-54ba-abe7-5517eb3f1af9'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'leading-vowel-family', 'The Leading-Vowel Family', 'เ, ไ, ใ, and โ are all written before the consonant', 'You now know four leading vowels: เ (e), ไ and ใ (ai), and โ (o). All four break the left-to-right order — write them first, but read the following consonant before adding the vowel.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('e5c49a63-f082-5af8-acd5-736ab3b9f0ff'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'mid-p', 'ป Is a Tight, Unaspirated p', 'ป has no puff of air, like the p in ''spin''', 'ป is a mid-class p with no aspiration. To an English ear it sits between b and p, like the p in ''spin''. It is distinct from the airy ผ you already know.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('c890a4d0-1151-5225-a234-0a15bdc7bde5'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'p-vs-b', 'ป and บ Look and Sound Close', 'ป (bp) and บ (b) are easy to mix up', 'ป and บ have similar shapes and similar sounds. ป is taller with a flag on top and is slightly tighter. Compare ปิด (closed) with บิน (to fly) to feel the difference.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('834616d7-e6ee-59ea-acc1-9766723d17a3'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'open-closed-pair', 'เปิด / ปิด: Open and Closed', 'Adding the leading vowel เ turns ปิด (closed) into เปิด (open)', 'This is the highest-value sign pair you can learn. ปิด means closed; put the leading vowel เ in front and you get เปิด, meaning open. You''ll read both on doors every day.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('fe76a3d2-1584-562c-aedb-afdee78c0e80'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'y-sound', 'ย Is a y Glide', 'ย gives the y sound at the start of a syllable', 'At the start of a syllable, ย is the y in ''yes''. It is a low-class consonant. The same letter can also close a syllable as a y-glide.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('278b5a51-aef0-5335-a42d-9e94a29d7ef6'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'glide-final-y-w', 'ย and ว Can Close a Syllable as Glides', 'Final ย adds an i/y glide; final ว adds a w glide', 'At the end of a syllable, ย and ว do not act as full consonants. ย adds a short i/y glide (as in ขาย) and ว adds a w glide (as in ขาว). You first met the w-glide back in ข้าว.', '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz);

